#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    double V0, theta_deg, D;
    std::cin >> V0 >> theta_deg >> D;

    const double g = 9.80665;
    const double PI = M_PI;

    double theta = theta_deg * PI / 180.0;
    double V0x = V0 * cos(theta);
    double V0y = V0 * sin(theta);

    double T = 2.0 * V0y / g;
    double R = V0x * T;
    double error = R - D;

    if (std::abs(error) <= 0.5) {
        std::cout << "HIT" << std::endl;
    } else {
        std::cout << "MISS " << std::fixed << std::setprecision(2) << error << std::endl;
    }

    return 0;
}
